import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Login from './pages/Login';
import Appointments from './pages/Appointments';
import Queue from './pages/Queue';
import Triage from './pages/Triage';
import Consultation from './pages/Consultation';
import Prescriptions from './pages/Prescriptions';
import LabTests from './pages/LabTests';
import auth from './services/auth';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const currentUser = auth.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
    setLoading(false);
  }, []);

  const handleLogout = () => {
    auth.logout();
    setUser(null);
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        fontSize: '24px'
      }}>
        Loading Clinic Management System...
      </div>
    );
  }

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  return (
    <Router>
      <Layout>
        <div style={{ display: 'flex', height: '100vh' }}>
          <Sidebar userRole={user.role} />
          <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
            <Header user={user} onLogout={handleLogout} />
            <main style={{ flex: 1, padding: '20px', backgroundColor: '#f5f5f5' }}>
              <Routes>
                <Route path="/dashboard" element={<Dashboard userRole={user.role} />} />
                <Route path="/appointments" element={<Appointments userRole={user.role} />} />
                <Route path="/queue" element={<Queue userRole={user.role} />} />
                <Route path="/triage" element={<Triage userRole={user.role} />} />
                <Route path="/consultation" element={<Consultation userRole={user.role} />} />
                <Route path="/prescriptions" element={<Prescriptions userRole={user.role} />} />
                <Route path="/lab-orders" element={<LabTests userRole={user.role} />} />
                <Route path="/" element={<Navigate to="/dashboard" />} />
              </Routes>
            </main>
          </div>
        </div>
      </Layout>
    </Router>
  );
}

export default App;
